import { Jimp, mkJGD } from '@jimp/test-utils';
import configure from '@jimp/custom';

import crop from '../src';

const jimp = configure({ plugins: [crop] }, Jimp);

describe('Autocrop', () => {
  it('image with transparent surround color', async () => {
    const imgSrc = await jimp.read(
      mkJGD(
        '          ',
        '    в—Ҷв—   ',
        '   в—Ҷв–Ұв–Ұв—  ',
        '  в—Ҷв–Ұв–Ұв–Ұв–Ұв— ',
        '   в—Ҷв–Ұв–Ұв—  ',
        '    в—Ҷв—   ',
        '          '
      )
    );

    imgSrc
      .autocrop()
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD('  в—Ҷв— ', ' в—Ҷв–Ұв–Ұв—', 'в—Ҷв–Ұв–Ұв–Ұв–Ұв—Ҷ', ' в—Ҷв–Ұв–Ұв—', '  в—Ҷв— ')
      );
  });

  it('image with opaque surround color', async () => {
    const imgSrc = await jimp.read(
      mkJGD(
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв—Ҷв—Ҷв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв—Ҷв–Ұв–Ұв—Ҷв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв—Ҷв–Ұв–Ұв–Ұв–Ұв—Ҷв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв—Ҷв–Ұв–Ұв—Ҷв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв—Ҷв—Ҷв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
      )
    );

    imgSrc
      .autocrop()
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD('в–Ҙв–Ҙв—Ҷв—Ҷв–Ҙв–Ҙ', 'в–Ҙв—Ҷв–Ұв–Ұв—Ҷв–Ҙ', 'в—Ҷв–Ұв–Ұв–Ұв–Ұв—Ҷ', 'в–Ҙв—Ҷв–Ұв–Ұв—Ҷв–Ҙ', 'в–Ҙв–Ҙв—Ҷв—Ҷв–Ҙв–Ҙ')
      );
  });

  it('image with one color border', async () => {
    const imgSrc = await jimp.read(
      mkJGD(
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–  в—Ҷв—  в–Ҙв–Ҙ',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙ',
        'в–Ҙв–в—Ҷв–Ұв–Ұв–Ұв–Ұв—в–Ҙв–Ҙ',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙ',
        'в–Ҙв–  в—Ҷв—  в–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
      )
    );

    imgSrc
      .autocrop()
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD('   в—Ҷв—  ', '  в—Ҷв–Ұв–Ұв— ', ' в—Ҷв–Ұв–Ұв–Ұв–Ұв—', '  в—Ҷв–Ұв–Ұв— ', '   в—Ҷв—  ')
      );
  });

  it('image border with small variation', async () => {
    const imgSrc = await jimp.read(
      mkJGD(
        '323232323232',
        '232323232323',
        '32   в—Ҷв—  32',
        '23  в—Ҷв–Ұв–Ұв— 23',
        '32 в—Ҷв–Ұв–Ұв–Ұв–Ұв—32',
        '23  в—Ҷв–Ұв–Ұв— 23',
        '32   в—Ҷв—  32',
        '232323232323',
        '323232323232'
      )
    );
    imgSrc
      .clone()
      .autocrop()
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD(
          '323232323232',
          '232323232323',
          '32   в—Ҷв—  32',
          '23  в—Ҷв–Ұв–Ұв— 23',
          '32 в—Ҷв–Ұв–Ұв–Ұв–Ұв—32',
          '23  в—Ҷв–Ұв–Ұв— 23',
          '32   в—Ҷв—  32',
          '232323232323',
          '323232323232'
        )
      );
    imgSrc
      .clone()
      .autocrop(0.005)
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD('   в—Ҷв—  ', '  в—Ҷв–Ұв–Ұв— ', ' в—Ҷв–Ұв–Ұв–Ұв–Ұв—', '  в—Ҷв–Ұв–Ұв— ', '   в—Ҷв—  ')
      );
  });

  it('image border with small variation configured by options', async () => {
    const imgSrc = await Jimp.read(
      mkJGD(
        '323232323232',
        '232323232323',
        '32   в—Ҷв—  32',
        '23  в—Ҷв–Ұв–Ұв— 23',
        '32 в—Ҷв–Ұв–Ұв–Ұв–Ұв—32',
        '23  в—Ҷв–Ұв–Ұв— 23',
        '32   в—Ҷв—  32',
        '232323232323',
        '323232323232'
      )
    );
    imgSrc
      .clone()
      .autocrop()
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD(
          '323232323232',
          '232323232323',
          '32   в—Ҷв—  32',
          '23  в—Ҷв–Ұв–Ұв— 23',
          '32 в—Ҷв–Ұв–Ұв–Ұв–Ұв—32',
          '23  в—Ҷв–Ұв–Ұв— 23',
          '32   в—Ҷв—  32',
          '232323232323',
          '323232323232'
        )
      );
    imgSrc
      .clone()
      .autocrop({ tolerance: 0.005 })
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD('   в—Ҷв—  ', '  в—Ҷв–Ұв–Ұв— ', ' в—Ҷв–Ұв–Ұв–Ұв–Ұв—', '  в—Ҷв–Ұв–Ұв— ', '   в—Ҷв—  ')
      );
  });

  it('image without frame', async () => {
    const imgSrc = await Jimp.read(
      mkJGD(
        'в–Ҙв–  в—Ҷв—  ',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— ',
        'в–Ҙв–в—Ҷв–Ұв–Ұв–Ұв–Ұв—',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— ',
        'в–Ҙв–  в—Ҷв—  ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
      )
    );

    imgSrc
      .autocrop(false)
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD('   в—Ҷв—  ', '  в—Ҷв–Ұв–Ұв— ', ' в—Ҷв–Ұв–Ұв–Ұв–Ұв—', '  в—Ҷв–Ұв–Ұв— ', '   в—Ҷв—  ')
      );
  });

  it('image without frame configured by options', async () => {
    const imgSrc = await Jimp.read(
      mkJGD(
        'в–Ҙв–  в—Ҷв—  ',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— ',
        'в–Ҙв–в—Ҷв–Ұв–Ұв–Ұв–Ұв—',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— ',
        'в–Ҙв–  в—Ҷв—  ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
      )
    );

    imgSrc
      .autocrop({ cropOnlyFrames: false })
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD('   в—Ҷв—  ', '  в—Ҷв–Ұв–Ұв— ', ' в—Ҷв–Ұв–Ұв–Ұв–Ұв—', '  в—Ҷв–Ұв–Ұв— ', '   в—Ҷв—  ')
      );
  });

  it('image with symmetric border configured by options', async () => {
    const imgSrc = await Jimp.read(
      mkJGD(
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–  в—Ҷв—  в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–в—Ҷв–Ұв–Ұв–Ұв–Ұв—в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–  в—Ҷв—  в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
      )
    );

    imgSrc
      .autocrop({ cropSymmetric: true })
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD(
          '   в—Ҷв—  в–Ҙв–Ҙ',
          '  в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙ',
          ' в—Ҷв–Ұв–Ұв–Ұв–Ұв—в–Ҙв–Ҙ',
          '  в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙ',
          '   в—Ҷв—  в–Ҙв–Ҙ',
          'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
        )
      );
  });

  it('image without frame and with symmetric border configured by options', async () => {
    const imgSrc = await Jimp.read(
      mkJGD(
        'в–Ҙв–  в—Ҷв—  в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–в—Ҷв–Ұв–Ұв–Ұв–Ұв—в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв– в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–  в—Ҷв—  в–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
      )
    );
    imgSrc
      .autocrop({ cropSymmetric: true, cropOnlyFrames: false })
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD(
          '   в—Ҷв—  в–Ҙв–Ҙ',
          '  в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙ',
          ' в—Ҷв–Ұв–Ұв–Ұв–Ұв—в–Ҙв–Ҙ',
          '  в—Ҷв–Ұв–Ұв— в–Ҙв–Ҙ',
          '   в—Ҷв—  в–Ҙв–Ҙ',
          'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
          'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
        )
      );
  });

  it('image without frame and with some border left', async () => {
    const imgSrc = await Jimp.read(
      mkJGD(
        '323232323232',
        '232323232323',
        '32   в—Ҷв—  32',
        '23  в—Ҷв–Ұв–Ұв— 23',
        '32 в—Ҷв–Ұв–Ұв–Ұв–Ұв—32',
        '23  в—Ҷв–Ұв–Ұв— 23',
        '32   в—Ҷв—  32',
        '232323232323',
        '323232323232'
      )
    );

    imgSrc
      .autocrop({
        tolerance: 0.005,
        leaveBorder: 1
      })
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD(
          '3232323232',
          '2   в—Ҷв—  3',
          '3  в—Ҷв–Ұв–Ұв— 2',
          '2 в—Ҷв–Ұв–Ұв–Ұв–Ұв—3',
          '3  в—Ҷв–Ұв–Ұв— 2',
          '2   в—Ҷв—  3',
          '3232323232'
        )
      );
  });

  it('image not cropped given an out of bounds "leaveBorder" value ', async () => {
    const imgSrc = await Jimp.read(
      mkJGD(
        '323232323232',
        '232323232323',
        '32   в—Ҷв—  32',
        '23  в—Ҷв–Ұв–Ұв— 23',
        '32 в—Ҷв–Ұв–Ұв–Ұв–Ұв—32',
        '23  в—Ҷв–Ұв–Ұв— 23',
        '32   в—Ҷв—  32',
        '232323232323',
        '323232323232'
      )
    );

    imgSrc
      .autocrop({
        tolerance: 0.005,
        leaveBorder: 100
      })
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD(
          '323232323232',
          '232323232323',
          '32   в—Ҷв—  32',
          '23  в—Ҷв–Ұв–Ұв— 23',
          '32 в—Ҷв–Ұв–Ұв–Ұв–Ұв—32',
          '23  в—Ҷв–Ұв–Ұв— 23',
          '32   в—Ҷв—  32',
          '232323232323',
          '323232323232'
        )
      );
  });

  it('image with top and bottom frame and leaveBorder', async () => {
    const imgSrc = await Jimp.read(
      mkJGD(
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        '   в—Ҷв—  ',
        '  в—Ҷв–Ұв–Ұв— ',
        ' в—Ҷв–Ұв–Ұв–Ұв–Ұв—',
        '  в—Ҷв–Ұв–Ұв— ',
        '   в—Ҷв—  ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
        'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
      )
    );
    imgSrc
      .autocrop({ cropSymmetric: true, cropOnlyFrames: false, leaveBorder: 2 })
      .getJGDSync()
      .should.be.sameJGD(
        mkJGD(
          'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
          'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
          '   в—Ҷв—  ',
          '  в—Ҷв–Ұв–Ұв— ',
          ' в—Ҷв–Ұв–Ұв–Ұв–Ұв—',
          '  в—Ҷв–Ұв–Ұв— ',
          '   в—Ҷв—  ',
          'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ',
          'в–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙв–Ҙ'
        )
      );
  });
});
